        return 1;
    }
    printf("recvmsg (peek) succeeded, got %d bytes\n", ret);

    /* Now do another recvmsg without PEEK to consume */
    memset(&msg, 0, sizeof(msg));
    memset(cmsg_buf, 0, sizeof(cmsg_buf));
    iov.iov_base = buf;
    iov.iov_len = sizeof(buf);
    msg.msg_iov = &iov;
    msg.msg_iovlen = 1;
    msg.msg_control = cmsg_buf;
